export type AnimalType = 'Dog' | 'Cat' | 'Bird' | 'Livestock' | 'Exotic' | 'Wild';
export type Environment = 'Indoor' | 'Outdoor' | 'Farm' | 'Forest' | 'Urban';
export type Status = 'Calm' | 'Alert' | 'Distressed' | 'Emergency';

export interface AnimalProfile {
  name: string;
  type: AnimalType;
  environment: Environment;
  age?: string;
  breed?: string;
}

export interface SoundAnalysisResult {
  emotion: string;
  intent: string;
  confidence: number;
  explanation: string;
  status: Status;
}

export interface TrainingSample {
  id: string;
  timestamp: number;
  userExplanation: string;
  fileName: string;
  status: 'pending' | 'verified';
}

import { GoogleGenAI, Type } from "@google/genai";
import { AnimalProfile, SoundAnalysisResult, Status } from "../types";

const API_KEY = process.env.API_KEY || "";
const ai = new GoogleGenAI({ apiKey: API_KEY });

export const analyzeAnimalBehavior = async (
  profile: AnimalProfile,
  mediaData: string,
  mimeType: string,
  isAudio: boolean
): Promise<SoundAnalysisResult> => {
  const model = "gemini-3-flash-preview";

  const prompt = `Analyze this ${isAudio ? 'audio recording' : 'video clip'} of a ${profile.type} named ${profile.name} (Breed: ${profile.breed || 'Unknown'}) in a ${profile.environment} environment.
  Determine the animal's emotional state, intent, and current risk level.
  Respond with a structured JSON object.`;

  const response = await ai.models.generateContent({
    model,
    contents: {
      parts: [
        { inlineData: { data: mediaData.split(',')[1] || mediaData, mimeType } },
        { text: prompt }
      ]
    },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          emotion: { type: Type.STRING },
          intent: { type: Type.STRING },
          confidence: { type: Type.NUMBER },
          explanation: { type: Type.STRING },
          status: { type: Type.STRING, description: "One of: Calm, Alert, Distressed, Emergency" }
        },
        required: ["emotion", "intent", "confidence", "explanation", "status"]
      }
    }
  });

  try {
    return JSON.parse(response.text);
  } catch (e) {
    console.error("Failed to parse Gemini response", e);
    throw new Error("Invalid analysis format received");
  }
};

