import React, { useState, useRef } from 'react';
import { AnimalProfile } from '../types';

interface TranslatorProps {
  profile: AnimalProfile;
  onAnalyze: (media: string, mime: string, isAudio: boolean) => Promise<void>;
}

const Translator: React.FC<TranslatorProps> = ({ profile, onAnalyze }) => {
  const [isRecording, setIsRecording] = useState(false);
  const [analyzing, setAnalyzing] = useState(false);
  const [previewUrl, setPreviewUrl] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setAnalyzing(true);
    const reader = new FileReader();
    reader.onload = async () => {
      const data = reader.result as string;
      setPreviewUrl(data);
      const isAudio = file.type.startsWith('audio');
      await onAnalyze(data, file.type, isAudio);
      setAnalyzing(false);
    };
    reader.readAsDataURL(file);
  };

  const toggleRecording = () => {
    // Simulated recording logic for this POC
    setIsRecording(!isRecording);
    if (!isRecording) {
      setTimeout(() => {
        setIsRecording(false);
        alert("Audio capture complete. In a real app, this would stream to Gemini Live API.");
      }, 3000);
    }
  };

  return (
    <div className="space-y-6 flex flex-col items-center">
      <div className="w-full text-center">
        <h2 className="text-2xl font-bold">Sound Translator</h2>
        <p className="text-slate-500">Translating {profile.name}'s thoughts into human words.</p>
      </div>

      {/* Recording Circle */}
      <div className="relative flex items-center justify-center h-64 w-64">
        {isRecording && (
          <div className="absolute inset-0 bg-indigo-100 rounded-full animate-ping opacity-25"></div>
        )}
        <button
          onClick={toggleRecording}
          disabled={analyzing}
          className={`relative z-10 w-48 h-48 rounded-full flex flex-col items-center justify-center transition-all shadow-2xl ${
            isRecording ? 'bg-red-500 scale-110 shadow-red-200' : 'bg-indigo-600 hover:bg-indigo-700 shadow-indigo-200'
          }`}
        >
          <i className={`fa-solid ${isRecording ? 'fa-stop' : 'fa-microphone'} text-5xl text-white mb-2`}></i>
          <span className="text-white text-xs font-bold tracking-widest uppercase">
            {isRecording ? 'Listening...' : analyzing ? 'Analyzing...' : 'Tap to Listen'}
          </span>
        </button>
      </div>

      {/* File Upload Alternative */}
      <div className="w-full max-w-sm">
        <div className="relative text-center my-4">
          <span className="px-2 bg-slate-50 text-slate-400 text-xs font-bold uppercase tracking-widest relative z-10">Or upload media</span>
          <div className="absolute top-1/2 left-0 right-0 h-px bg-slate-200 -z-0"></div>
        </div>

        <input
          type="file"
          ref={fileInputRef}
          onChange={handleFileUpload}
          className="hidden"
          accept="audio/*,video/*"
        />
        <button
          onClick={() => fileInputRef.current?.click()}
          className="w-full bg-white border-2 border-dashed border-slate-300 py-6 rounded-3xl text-slate-500 hover:border-indigo-400 hover:text-indigo-600 transition-all flex flex-col items-center gap-2"
        >
          <i className="fa-solid fa-cloud-arrow-up text-2xl"></i>
          <span className="font-medium">Upload Audio or Video</span>
        </button>
      </div>

